"use client"

import { Skeleton } from "@/components/ui/skeleton"
import { useState } from "react"
import Canvas from "./editor"
import { PdfLoader } from "./pdf-loader"
import { PdfShapes } from "./pdf-shapes"

type CanvasState =
  | { status: "empty" }
  | { status: "loading" }
  | { status: "loaded"; bytes: Uint8Array }
  | { status: "error"; message: string }

export function CanvasHost() {
  const [state, setState] = useState<CanvasState>({ status: "empty" })

  function handleFile(bytes: Uint8Array) {
    setState({ status: "loaded", bytes })
  }

  async function handleExample() {
    setState({ status: "loading" })
    try {
      const res = await fetch("/sample.pdf")
      if (!res.ok) throw new Error(`fetch failed: ${res.status}`)
      const buf = await res.arrayBuffer()
      setState({ status: "loaded", bytes: new Uint8Array(buf) })
    } catch (err) {
      setState({
        status: "error",
        message: err instanceof Error ? err.message : "Failed to load sample.",
      })
    }
  }

  function handleError(message: string) {
    setState({ status: "error", message })
  }

  if (state.status === "empty" || state.status === "error") {
    return (
      <PdfLoader
        onFile={handleFile}
        onExample={handleExample}
        onError={handleError}
        error={state.status === "error" ? state.message : undefined}
      />
    )
  }

  if (state.status === "loading") {
    return (
      <div className="flex min-h-svh items-center justify-center">
        <div className="flex w-full max-w-sm flex-col gap-3 p-8">
          <Skeleton className="h-6 w-3/4" />
          <Skeleton className="h-4 w-full" />
          <Skeleton className="h-4 w-5/6" />
          <Skeleton className="mt-4 h-64 w-full rounded-xl" />
        </div>
      </div>
    )
  }

  return (
    <Canvas>
      <PdfShapes bytes={state.bytes} />
    </Canvas>
  )
}

import type { PDFDocumentProxy } from "pdfjs-dist"

// Dynamic import keeps pdfjs-dist out of the SSR bundle — it accesses DOMMatrix
// and other browser globals at module evaluation time, crashing Next.js builds.
async function pdfjs() {
  return import("pdfjs-dist")
}

let workerSet = false

async function ensureWorker() {
  if (workerSet) return
  const { GlobalWorkerOptions } = await pdfjs()
  GlobalWorkerOptions.workerSrc = "/pdf.worker.min.mjs"
  workerSet = true
}

export interface PageDimensions {
  w: number
  h: number
  x: number
  y: number
}

const GUTTER = 20

export async function openPdf(bytes: Uint8Array): Promise<PDFDocumentProxy> {
  await ensureWorker()
  const { getDocument } = await pdfjs()
  return getDocument({ data: bytes }).promise
}

export async function getPageLayout(
  pdf: PDFDocumentProxy
): Promise<PageDimensions[]> {
  const pages = await Promise.all(
    Array.from({ length: pdf.numPages }, (_, i) => pdf.getPage(i + 1))
  )

  const layout: PageDimensions[] = []
  let yOffset = 0

  for (const page of pages) {
    const vp = page.getViewport({ scale: 1 })
    layout.push({ w: vp.width, h: vp.height, x: -vp.width / 2, y: yOffset })
    yOffset += vp.height + GUTTER
  }

  return layout
}

export async function renderPage(
  pdf: PDFDocumentProxy,
  pageNumber: number,
  { dprCap = 3 }: { dprCap?: number } = {}
): Promise<Blob> {
  const scale = Math.min(devicePixelRatio * 2, dprCap)
  const page = await pdf.getPage(pageNumber)
  const viewport = page.getViewport({ scale })
  const canvas = new OffscreenCanvas(
    Math.round(viewport.width),
    Math.round(viewport.height)
  )
  const ctx = canvas.getContext("2d")
  if (!ctx) throw new Error("OffscreenCanvas 2d context unavailable")
  // pdfjs types require HTMLCanvasElement but accepts OffscreenCanvas at runtime
  await page.render({
    canvasContext: ctx as unknown as CanvasRenderingContext2D,
    canvas: canvas as unknown as HTMLCanvasElement,
    viewport,
  }).promise
  return canvas.convertToBlob({ type: "image/png" })
}

"use client"

import { useEditor } from "@/components/canvas/editor"
import {
  type PageDimensions,
  getPageLayout,
  openPdf,
  renderPage,
} from "@/lib/pdf/render"
import type { PDFDocumentProxy } from "pdfjs-dist"
import { useEffect } from "react"
import { AssetRecordType, createShapeId } from "tldraw"
import type { Editor } from "tldraw"

const INITIAL_PAGES = 10

interface PdfShapesProps {
  bytes: Uint8Array
}

async function createPageShape(
  editor: Editor,
  pageIndex: number,
  blob: Blob,
  dims: PageDimensions,
  urls: string[]
) {
  const url = URL.createObjectURL(blob)
  urls.push(url)
  const assetId = AssetRecordType.createId()

  editor.createAssets([
    AssetRecordType.create({
      id: assetId,
      type: "image",
      props: {
        src: url,
        w: dims.w,
        h: dims.h,
        mimeType: "image/png",
        isAnimated: false,
        name: `page-${pageIndex + 1}.png`,
      },
    }),
  ])

  editor.createShapes([
    {
      id: createShapeId(),
      type: "image",
      x: dims.x,
      y: dims.y,
      props: { assetId, w: dims.w, h: dims.h },
    },
  ])
}

export function PdfShapes({ bytes }: PdfShapesProps) {
  const editor = useEditor()

  useEffect(() => {
    if (!editor) return

    const ed = editor
    let aborted = false
    let pdf: PDFDocumentProxy
    let unsubscribe: (() => void) | undefined
    const renderedPages = new Set<number>()
    const objectUrls: string[] = []
    let layout: PageDimensions[] = []

    async function renderAndCreate(pageIndex: number) {
      if (aborted || renderedPages.has(pageIndex)) return
      const dims = layout[pageIndex]
      if (!dims) return
      renderedPages.add(pageIndex)
      const blob = await renderPage(pdf, pageIndex + 1)
      if (aborted) return
      await createPageShape(ed, pageIndex, blob, dims, objectUrls)
    }

    async function init() {
      pdf = await openPdf(bytes)
      if (aborted) return

      layout = await getPageLayout(pdf)
      if (aborted) return

      const initialCount = Math.min(INITIAL_PAGES, pdf.numPages)
      for (let i = 0; i < initialCount; i++) {
        await renderAndCreate(i)
        if (aborted) return
      }

      ed.zoomToFit({ animation: { duration: 0 } })

      if (pdf.numPages <= INITIAL_PAGES) return

      let debounceTimer: ReturnType<typeof setTimeout> | null = null

      unsubscribe = ed.store.listen(() => {
        if (debounceTimer) clearTimeout(debounceTimer)
        debounceTimer = setTimeout(() => {
          if (aborted) return
          const vp = ed.getViewportPageBounds()
          for (let i = INITIAL_PAGES; i < layout.length; i++) {
            if (renderedPages.has(i)) continue
            const page = layout[i]
            if (!page) continue
            if (
              page.x < vp.maxX &&
              page.x + page.w > vp.minX &&
              page.y < vp.maxY &&
              page.y + page.h > vp.minY
            ) {
              renderAndCreate(i)
            }
          }
        }, 150)
      })
    }

    init()

    return () => {
      aborted = true
      unsubscribe?.()
      for (const url of objectUrls) URL.revokeObjectURL(url)
    }
  }, [editor, bytes])

  return null
}

